1385	 *
1386	 * @param agent - Agent name to filter by
1387	 * @param windowDays - Rolling window in days (default 30)
1388	 */
1389	export function querySoulDrift(agent: string, windowDays = 30): { added: number; removed: number } {
1390	  const raw = getRawDb();
1391	  const since = new Date(Date.now() - windowDays * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
1392	
1393	  const row = raw.prepare(`
1394	    SELECT COALESCE(SUM(lines_added), 0) as added, COALESCE(SUM(lines_removed), 0) as removed
1395	    FROM soul_changes
1396	    WHERE agent = ? AND date >= ? AND status = 'auto-applied'
1397	  `).get(agent, since) as { added: number; removed: number } | null;
1398	
1399	  return { added: row?.added ?? 0, removed: row?.removed ?? 0 };
1400	}
1401	
1402	/**
1403	 * Get recent soul change records.
1404	 *
1405	 * @param agent - Optional agent filter
1406	 * @param opts.limit - Max rows to return (default 20)
1407	 * @param opts.since - Optional ISO date string lower bound on created_at
