 *
 * @param agent - Agent name to filter by
 * @param windowDays - Rolling window in days (default 30)
 */
export function querySoulDrift(agent: string, windowDays = 30): { added: number; removed: number } {
  const raw = getRawDb();
  const since = new Date(Date.now() - windowDays * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

  const row = raw.prepare(`
    SELECT COALESCE(SUM(lines_added), 0) as added, COALESCE(SUM(lines_removed), 0) as removed
    FROM soul_changes
    WHERE agent = ? AND date >= ? AND status = 'auto-applied'
  `).get(agent, since) as { added: number; removed: number } | null;

  return { added: row?.added ?? 0, removed: row?.removed ?? 0 };
}

